solution_code:
#include <iostream>

class TrackedInt
{
    int* m_ptr{};

public:
    TrackedInt(int value)
        : m_ptr{ new int{ value } }
    {
        std::cout << "allocated " << value << '\n';
    }

    ~TrackedInt()
    {
        std::cout << "deallocated" << '\n';
        delete m_ptr;
    }

    int getValue() const { return *m_ptr; }
};

int main()
{
    int n{};
    std::cin >> n;

    TrackedInt t{ n };
    std::cout << "value: " << t.getValue() << '\n';

    return 0;
}

