solution_code:
#include <iostream>

struct OwnedArray
{
    int* data{};
    int size{};
};

OwnedArray createArray(int n)
{
    return OwnedArray{ new int[n]{}, n };
}

int main()
{
    int n{};
    std::cin >> n;

    OwnedArray arr{ createArray(n) };

    for (int i{ 0 }; i < arr.size; ++i)
        std::cin >> arr.data[i];

    for (int i{ 0 }; i < arr.size; ++i)
    {
        if (i > 0)
            std::cout << ' ';
        std::cout << arr.data[i];
    }
    std::cout << '\n';

    delete[] arr.data;
    arr.data = nullptr;
    std::cout << "cleaned up" << '\n';

    return 0;
}
